        <textarea v-model="answers[6]" class="gp-side-answer" placeholder="답변을 입력하세요..." rows="3" />
      </li>
      <li class="gp-side-item">
        <div class="gp-side-meta"><span class="gp-side-cat">권한</span><span class="gp-side-pri gp-side-pri--high">높음</span></div>
        <p class="gp-side-q">이 화면의 접근 권한과 노출 범위를 어떻게 통제할까요(예: 특정 역할만 접근, 본인 로그만 조회 가능, 특정 부서 범위만 조회 가능 등) 그리고 권한이 없을 때의 처리(메뉴 숨김/접근 차단 메시지/감사로그 남김)는 어떻게 할까요?</p>
        <textarea v-model="answers[7]" class="gp-side-answer" placeholder="답변을 입력하세요..." rows="3" />
      </li>
      <li class="gp-side-item">
        <div class="gp-side-meta"><span class="gp-side-cat">엑셀</span><span class="gp-side-pri gp-side-pri--high">높음</span></div>
        <p class="gp-side-q">엑셀 다운로드는 ‘현재 페이지’만 받을지 ‘검색조건에 해당하는 전체 결과’를 받을지, 최대 다운로드 건수 제한/비동기 생성(대용량)/개인정보 마스킹/다운로드 이력 남김/권한(관리자만 등) 정책을 각각 어떻게 적용할까요?</p>
        <textarea v-model="answers[8]" class="gp-side-answer" placeholder="답변을 입력하세요..." rows="3" />
      </li>
      <li class="gp-side-item">
        <div class="gp-side-meta"><span class="gp-side-cat">예외처리</span><span class="gp-side-pri gp-side-pri--mid">보통</span></div>
        <p class="gp-side-q">조회 결과 0건, 서버/API 오류, 네트워크 지연/타임아웃, 권한 오류가 발생했을 때 각각 사용자에게 어떤 메시지와 행동을 제공할까요(예: 재시도 버튼, 안내 문구, 페이지네이션 영역 숨김 여부, 엑셀 버튼 비활성화 기준)?</p>
        <textarea v-model="answers[9]" class="gp-side-answer" placeholder="답변을 입력하세요..." rows="3" />
      </li>
      </ol>

      <!-- 자유 추가 질문 영역 -->
      <div v-if="customQAs.length" class="gp-side-custom">
        <div class="gp-side-custom-divider">현장 추가 질문</div>
        <ol class="gp-side-list gp-side-list--custom">
          <li v-for="(item, i) in customQAs" :key="i" class="gp-side-item gp-side-item--custom">
            <div class="gp-side-custom-q-row">
              <input
                v-model="item.question"
                class="gp-side-custom-q-input"
                placeholder="질문을 입력하세요..."
              />
              <button class="gp-side-del-btn" title="삭제" @click="removeQA(i)">✕</button>
            </div>
            <textarea
              v-model="item.answer"
              class="gp-side-answer"
              placeholder="답변을 입력하세요..."
              rows="3"
            />
          </li>
        </ol>
      </div>
      <div v-else class="gp-side-custom-empty">
        <button class="gp-side-add-btn gp-side-add-btn--ghost" @click="addQA">+ 현장 질문 추가</button>
      </div>

      <!-- 인터뷰결과생성 -->
      <div class="gp-side-result-area">
        <div v-if="resultStatus === 'success'" class="gp-side-result-msg gp-side-result-msg--ok">
          ✓ InterviewNote.md 생성 완료<br>
          <small>src/spec-source/UserAccessLogList/</small>
        </div>
        <div v-else-if="resultStatus === 'error'" class="gp-side-result-msg gp-side-result-msg--err">
          {{ resultMessage }}
        </div>
        <button
          class="gp-side-generate-btn"
          :class="{ 'gp-side-generate-btn--ready': interviewCompleted }"
          :disabled="resultGenerating || !interviewCompleted"
          @click="generateInterviewResult"
        >
          {{ resultGenerating ? '생성 중...' : '인터뷰결과생성' }}
        </button>
        <p v-if="!interviewCompleted" class="gp-side-generate-hint">
          모든 질문에 답변을 작성해야 실행됩니다.
        </p>
      </div>
    </aside>
  </div>
</template>

<script lang="ts" setup>
import { ref, computed, reactive } from 'vue';

const INTERVIEW_RESULT_API = 'http://localhost:4000/api/generate-interview-result';
import { StandardListTemplate } from '@/components/templates';

const PAGE_SIZE = 10;
const page = ref(1);

const answers = ref<string[]>(Array(10).fill(''));
const answerCopied = ref(false);
const resultGenerating = ref(false);
const resultStatus = ref<'' | 'success' | 'error'>('');
const resultMessage = ref('');
const interviewCompleted = computed(() => answers.value.every(a => a.trim() !== ''));

interface CustomQA { question: string; answer: string; }
const customQAs = ref<CustomQA[]>([]);

const QUESTIONS = [
  '이 화면의 주된 사용 목적과 주요 이용자 역할 및 핵심 정보(컬럼/필터)는 무엇인가요?',
  '접속자ID의 정의와 저장 포맷, 검색 시 대소문자/정확일치/부분일치 규칙은 무엇인가요?',
  '접속자명 기준, 공백/초성/유사검색 여부, 대소문자/정규화 범위는 어떻게 할까요?',
  '조회 실행 방식(Enter 조회, 자동조회 등)과 그 우선순위는 무엇인가요?',
  '조회/초기화 시 화면 상태 변화(페이지이동, 스크롤, 로딩, 결과유지)의 기대 동작은?',
  '초기화 후 완전 공백 vs 기본 조회조건 세팅, 기본값이 있다면 항목과 값은?',
  '접속 로그 필수/선택 컬럼과 각 컬럼 포맷(일시, IP 마스킹 등)은?',
  '접근 권한 통제 범위와 권한 없을 때의 처리 방식은?',
  '엑셀 다운로드 대상(현재 페이지/전체), 건수 제한/마스킹/권한 정책은?',
  '조회 0건/API 오류/타임아웃/권한 오류 시 사용자에게 제공할 메시지와 행동은?',
];

const QUESTION_META = [
  { no: 1, category: '조회', question: QUESTIONS[0], priority: '높음', tip: '' },
  { no: 2, category: '데이터정의', question: QUESTIONS[1], priority: '높음', tip: '' },
  { no: 3, category: '데이터정의', question: QUESTIONS[2], priority: '보통', tip: '' },
  { no: 4, category: '사용자행동', question: QUESTIONS[3], priority: '보통', tip: '' },
  { no: 5, category: '사용자행동', question: QUESTIONS[4], priority: '보통', tip: '' },
  { no: 6, category: '사용자행동', question: QUESTIONS[5], priority: '높음', tip: '' },
  { no: 7, category: '데이터정의', question: QUESTIONS[6], priority: '높음', tip: '' },
  { no: 8, category: '권한', question: QUESTIONS[7], priority: '높음', tip: '' },
  { no: 9, category: '데이터정의', question: QUESTIONS[8], priority: '높음', tip: '' },
  { no: 10, category: '예외처리', question: QUESTIONS[9], priority: '보통', tip: '' },
];

function addQA() {
  customQAs.value.push({ question: '', answer: '' });
}

function removeQA(idx: number) {
  customQAs.value.splice(idx, 1);
}

async function generateInterviewResult() {
  if (!interviewCompleted.value || resultGenerating.value) return;
  resultGenerating.value = true;
  resultStatus.value = '';
  resultMessage.value = '';
  try {
    const questions = QUESTION_META.map((m, i) => ({ ...m, answer: answers.value[i] ?? '' }));
    const res = await fetch(INTERVIEW_RESULT_API, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        screenName: 'UserAccessLogList',
        pageName:   'UserAccessLogList',
        title:      '사용자 접속 로그 조회',
        pageType:   'list',
        questions,
        customQAs:  customQAs.value,
      }),
    });
    const data = await res.json();
    if (data.success) { resultStatus.value = 'success'; }
    else { resultStatus.value = 'error'; resultMessage.value = data.message ?? '생성에 실패했습니다.'; }
  } catch (e) {
    resultStatus.value = 'error';
    resultMessage.value = `요청 실패: ${(e as Error).message}`;
  } finally {
    resultGenerating.value = false;
  }
}

function copyAnswers() {
  const fixed = QUESTIONS
    .map((q, i) => `Q${i + 1}. ${q}\nA: ${answers.value[i] || '(미작성)'}`)
    .join('\n\n');
  const custom = customQAs.value.length
    ? '\n\n── 현장 추가 질문 ──\n\n' + customQAs.value
        .map((qa, i) => `추가${i + 1}. ${qa.question || '(질문 없음)'}\nA: ${qa.answer || '(미작성)'}`)
        .join('\n\n')
    : '';
  const text = fixed + custom;
  navigator.clipboard.writeText(text).then(() => {
    answerCopied.value = true;
    setTimeout(() => { answerCopied.value = false; }, 2000);
  }).catch(() => {
    const el = document.createElement('textarea');
    el.value = text;
    document.body.appendChild(el);
    el.select();
    document.execCommand('copy');
    document.body.removeChild(el);
    answerCopied.value = true;
    setTimeout(() => { answerCopied.value = false; }, 2000);
  });
}

const search = reactive<Record<string, string>>({
  field0: '',
  field1: ''
});

const MOCK_DATA: Record<string, string>[] = [
  {
    "col0": "접속자ID 1",
    "col1": "접속자명 1"
  },
  {
    "col0": "접속자ID 2",
    "col1": "접속자명 2"
  },
  {
    "col0": "접속자ID 3",
    "col1": "접속자명 3"
  },
  {
    "col0": "접속자ID 4",
    "col1": "접속자명 4"
  },
  {
    "col0": "접속자ID 5",
    "col1": "접속자명 5"
  },
  {
    "col0": "접속자ID 6",
    "col1": "접속자명 6"
  },
  {
    "col0": "접속자ID 7",
    "col1": "접속자명 7"
  },
  {
    "col0": "접속자ID 8",
    "col1": "접속자명 8"
  },
  {
    "col0": "접속자ID 9",
    "col1": "접속자명 9"
  },
  {
    "col0": "접속자ID 10",
    "col1": "접속자명 10"
  }
];

const filteredRows = computed(() =>
  MOCK_DATA.filter(row =>
    (!search.field0 || String(row.field0 ?? '').includes(String(search.field0))) &&
    (!search.field1 || String(row.field1 ?? '').includes(String(search.field1)))
  ),
);

const totalPages = computed(() =>
  Math.max(1, Math.ceil(filteredRows.value.length / PAGE_SIZE)),
);

const pagedRows = computed(() =>
  filteredRows.value.slice((page.value - 1) * PAGE_SIZE, page.value * PAGE_SIZE),
);

function onSearch() {
  page.value = 1;
}

function onReset() {
  search.field0 = '';
  search.field1 = '';
  page.value = 1;
}
</script>

